const name = 'Alice';
const age = 28;
const role = 'admin';

// Old verbose form:
const user = { name: name, age: age, role: role };

// Shorthand — identical result:
const user = { name, age, role };
// { name: 'Alice', age: 28, role: 'admin' }

function createUser(name, email, role = 'user') {
  const id = generateId();
  const createdAt = new Date();

  // Return all as an object using shorthand
  return { id, name, email, role, createdAt };
}

// In array operations:
const processed = raw.map(({ id, title, author }) => ({ id, title, author }));

// Verbose:
const calculator = {
  add: function(a, b) { return a + b; },
  subtract: function(a, b) { return a - b; },
};

// Shorthand:
const calculator = {
  add(a, b) { return a + b; },
  subtract(a, b) { return a - b; },
};

calculator.add(5, 3);      // 8
calculator.subtract(5, 3); // 2

const field = 'email';
const prefix = 'user';

// Static key (must be a literal):
const obj1 = { email: 'alice@example.com' };

// Computed key (evaluated at runtime):
const obj2 = { [field]: 'alice@example.com' };
console.log(obj2); // { email: 'alice@example.com' }

// With an expression:
const obj3 = { [`${prefix}_id`]: 42 };
console.log(obj3); // { user_id: 42 }

function setProperty(obj, key, value) {
  return { ...obj, [key]: value }; // key is dynamic
}

const user = { name: 'Alice', age: 28 };
const updated = setProperty(user, 'email', 'alice@example.com');
console.log(updated);
// { name: 'Alice', age: 28, email: 'alice@example.com' }

import { useState } from 'react';

function SignupForm() {
  const [form, setForm] = useState({
    name: '',
    email: '',
    password: '',
  });

  // One handler for ALL fields — uses computed property name
  function handleChange(e) {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value, // ← computed key: name is 'name', 'email', or 'password'
    }));
  }

  return (
    <form>
      <input name="name"     value={form.name}     onChange={handleChange} />
      <input name="email"    value={form.email}    onChange={handleChange} />
      <input name="password" value={form.password} onChange={handleChange} />
    </form>
  );
}

// Convert an array to a keyed lookup object
const users = [
  { id: 'u1', name: 'Alice' },
  { id: 'u2', name: 'Bob' },
];

const usersById = users.reduce((acc, user) => ({
  ...acc,
  [user.id]: user, // computed key from each user's id
}), {});

console.log(usersById);
// { u1: { id: 'u1', name: 'Alice' }, u2: { id: 'u2', name: 'Bob' } }

console.log(usersById['u1'].name); // 'Alice'

function Alert({ type, message }) {
  // Map status to CSS class
  const classMap = {
    info: 'alert-info',
    success: 'alert-success',
    warning: 'alert-warning',
    error: 'alert-error',
  };

  const className = classMap[type] || 'alert-info';

  return <div className={`alert ${className}`}>{message}</div>;
}

// With computed key for dynamic config:
function buildConfig(env) {
  return {
    apiUrl: process.env[`REACT_APP_API_URL_${env.toUpperCase()}`],
    debug: env !== 'production',
  };
}

function updateField(state, fieldName, fieldValue) {
  return {
    ...state,
    [fieldName]: fieldValue, // computed key
    updatedAt: new Date(),   // regular property
  };
}

// Or with shorthand mixed in:
function createEvent(type, payload) {
  const timestamp = Date.now();
  const id = `${type}-${timestamp}`;

  return {
    id,         // shorthand for id: id
    type,       // shorthand for type: type
    payload,    // shorthand for payload: payload
    timestamp,  // shorthand for timestamp: timestamp
    [type]: true, // computed key — e.g. { click: true } or { submit: true }
  };
}

const field = 'name';

// ❌ Creates a literal key 'field', not the value of the variable
const obj = { field: 'Alice' };
console.log(obj); // { field: 'Alice' } — not what you wanted!

// ✅ Brackets evaluate the expression
const obj = { [field]: 'Alice' };
console.log(obj); // { name: 'Alice' }

const firstName = 'Alice';

// ❌ Can't use shorthand when you want a different key name
const obj = { firstName }; // { firstName: 'Alice' } — but you might want { name: 'Alice' }

// ✅ Must use explicit key: value when the names differ
const obj = { name: firstName }; // { name: 'Alice' }
